def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def time_to_reach(current_position, target_position, speed):
        return calculate_distance(current_position, target_position) / speed

    TIME_PENALTY_MULTIPLIER = 2.0
    WAIT_TIME_THRESHOLD = 10.0
    scores = []

    for idx, customer in enumerate(unvisited_customers):
        travel_time = time_to_reach(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time

        window_start, window_end = time_windows[idx]
        window_mid_point = (window_start + window_end) / 2

        if arrival_time < window_start:
            wait_time = window_start - arrival_time
            # Favor waiting a little over violating time windows heavily
            if wait_time <= WAIT_TIME_THRESHOLD:
                penalty = -wait_time / 2
            else:
                penalty = -WAIT_TIME_THRESHOLD
        elif arrival_time > window_end:
            penalty = -(arrival_time - window_end) * TIME_PENALTY_MULTIPLIER
        else:
            penalty = 0  # Optimal timing

        score = penalty - travel_time
        scores.append(score)

    if not scores:
        return None

    best_score = max(scores)
    best_node = scores.index(best_score)

    return best_node
